var e=[{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`젠장! 여기도 함정이야!`,JPN:`ちくしょう！　こっちも罠だ！`,ENG:`Darn it, it’s another trap!`,TWN:`可惡！這裡也是陷阱！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`쿨럭, 쿨럭! 이 최루탄, 방독면을 써도 소용없어!`,JPN:`ゴホッ、ゴホッ！　この催涙弾、防毒マスクを使ってもダメだ！`,ENG:`*Cough, cough* The gas mask is no use against this tear bomb!`,TWN:`咳咳！咳咳！是催淚彈！戴上防毒面罩也沒有用！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:null,text:{KOREA:`낙석이다! 이대로는 중장비가 움직이지 못해!`,JPN:`落石だ！　このままでは重機を動かせない！`,ENG:`A rockslide! We can’t move the heavy machinery!`,TWN:`有落石！這樣怪手沒辦法動！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`계속 떨어진다! 다들 피해!`,JPN:`また落ちてくるぞ！　避けろ！`,ENG:`It keeps coming! Everyone, hide!`,TWN:`　　`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`PMC_SUMMER_NULL_L`,text:{KOREA:`빌어먹을, 하루만에 숲을 요새로 만들어 놓다니…….`,JPN:`くそ、たった一日で森を要塞化するとは……`,ENG:`They turned the forest into a fortress overnight...`,TWN:`該死的，竟然一天之內就設下這麼多陷阱……`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`PMC_SUMMER_NULL_L`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`PMC_SUMMER_NULL_L`,text:{KOREA:`휘둘리지 마! 적은 한 명뿐이다! 동요하지 말고 대열을 유지해!`,JPN:`惑わされるな！　敵は一人だけだ！　動揺せず、隊列を維持しろ！`,ENG:`Gather yourselves! It’s just one person! Keep calm and stay in formation!`,TWN:`大家穩住！敵人只有一個人！別慌，隊伍不要亂掉！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`PMC_SUMMER_NULL_L`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`PMC_SUMMER_NULL_NULL`,text:{KOREA:`대장님! 후미에 연막탄이 떨어졌습니다!`,JPN:`隊長！　後方に煙幕弾が落とされました！`,ENG:`Leader, they dropped a smoke bomb behind us!`,TWN:`隊長！煙霧彈落在尾部了!`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`PMC_SUMMER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`PMC_SUMMER_NULL_NULL`,text:{KOREA:`아니, 이건 연막탄이 아니라…… 졸음이…….`,JPN:`いや、これは煙幕弾じゃなくて……眠気が……`,ENG:`No, this is not a smoke bomb... I feel sleepy...`,TWN:`不，這不是煙霧彈… 好睏…`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`PMC_SUMMER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`PMC_SUMMER_NULL_L`,text:{KOREA:`큭……. 카운터답지 않은 수작을 부리는군.`,JPN:`くっ……カウンターらしくない小細工を……`,ENG:`Darn... I didn’t expect a Counter to use this sort of trick.`,TWN:`咳……身為制裁者竟然還耍這些花招！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`PMC_SUMMER_NULL_L`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`PMC_SUMMER_NULL_L`,text:{KOREA:`중장비는 내버려 둬! 건질 수 있는 것만 건져야 한다!`,JPN:`重機は放っておけ！　持っていける装備だけ確保しろ！`,ENG:`Leave the heavy machinery! We’ll just take what we can!`,TWN:`怪手就扔著吧！其他能帶走多少算多少！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`PMC_SUMMER_NULL_L`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`PMC_SUMMER_NULL_L`,text:{KOREA:`전속력으로 숲을 벗어나라! 엄폐물이 있는 장소에서는 우리가 불리해!`,JPN:`全力で森を抜けろ！　掩ぺい物がある場所では俺たちが不利だ！`,ENG:`Get out of the forest! We have move to an open space!`,TWN:`立刻從森林裡撤退！在有遮蔽物的地方對我們不利！`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`PMC_SUMMER_NULL_L`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`PMC_SUMMER_NULL_L`,text:{KOREA:`드라코! 응답해! 오늘도 농땡이 피울 생각은 아니겠지?!`,JPN:`ドラコ！　応答せよ！　まさか今日もサボるんじゃないだろうな！？`,ENG:`Dracasia, respond! Are you goofing off again?`,TWN:`德拉克，你在哪！該不會又再摸魚吧？`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`PMC_SUMMER_NULL_L`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`DRACO_NPC_SUMMER_NULL`,text:{KOREA:`누구더러 농땡이래? 그 나이 먹고 나한테 매달리는 게 쪽팔리지도 않아?`,JPN:`サボるだなんて失礼だな！　いい年したおっさんのくせに、あたしに頼るなんてみっともねえ。`,ENG:`Don’t call me a goof-off. Aren’t you embarrassed to ask a young girl for help?`,TWN:`誰摸魚啦？年紀一大把，還倚賴一個小孩子你不害羞嗎？`},stage:{bg:`FOREST_NORMAL`,slots:{L:{char_id:`PMC_SUMMER_NULL_L`,face:`UNIT_IDLE`},C:null,R:{char_id:`DRACO_NPC_SUMMER_NULL`,face:`UNIT_IDLE`}}}},{id:`L24_1`,type:`dialog`,speaker:`DRACO_NPC_SUMMER_NULL`,text:{KOREA:`귀찮게 구는 빨강머리가 붙어 있어. 처리한 다음에 다시 연락해.`,JPN:`手を焼かせる赤毛につけられてんの。処理した後連絡する。`,ENG:`I have a redhead on me to take care of. Let’s talk later when I’m done.`,TWN:`有一個紅頭髮的人在糾纏我，處理完再跟你聯絡啦！`},stage:{bg:`FOREST_NORMAL`,slots:{L:{char_id:`PMC_SUMMER_NULL_L`,face:`UNIT_IDLE`},C:null,R:{char_id:`DRACO_NPC_SUMMER_NULL`,face:`UNIT_IDLE`}}}},{id:`L29_1`,type:`dialog`,speaker:`SPEAR_FLORA_SUMMER_NULL`,text:{KOREA:`미안한데 처리한다고 하지 말아 줄래? 그 말 들으면 주방에 있을 때 생각나거든?`,JPN:`悪いけど、処理という言葉は使わないでくれる？　厨房にいる気持ちになるのよね。`,ENG:`Don’t say the word “done”, please. That expression reminds me of my kitchen days.`,TWN:`不好意思，可以不要說處理嗎？ 聽到處理我就會想到以前在廚房的時候。`},stage:{bg:`FOREST_NORMAL`,slots:{L:null,C:{char_id:`SPEAR_FLORA_SUMMER_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};